import { useState, useEffect, useMemo, useRef } from "react";
import { motion, AnimatePresence } from "framer-motion";
import { useNavigate } from "react-router-dom";
import {
  LayoutDashboard,
  ShoppingCart,
  Users,
  Package,
  BarChart3,
  Settings,
  User,
  LogOut,
} from "lucide-react";

import { adminDashboardDesign as design } from "../../design/adminDashboardDesign";

const menuItems = [
  { name: "Dashboard", icon: LayoutDashboard },
  { name: "Products", icon: Package },
  { name: "Orders", icon: ShoppingCart },
  { name: "Users", icon: Users },
  { name: "Analytics", icon: BarChart3 },
  { name: "Settings", icon: Settings },
];

const AdminDashboard = () => {
  const navigate = useNavigate();
  const adminInfo = JSON.parse(localStorage.getItem("adminInfo"));

  const [search, setSearch] = useState("");
  const [dropdownOpen, setDropdownOpen] = useState(false);
  const [sidebarOpen, setSidebarOpen] = useState(false);

  const dropdownRef = useRef(null);

  useEffect(() => {
    const handleClickOutside = (event) => {
      if (dropdownRef.current && !dropdownRef.current.contains(event.target)) {
        setDropdownOpen(false);
      }
    };
    document.addEventListener("mousedown", handleClickOutside);
    return () => document.removeEventListener("mousedown", handleClickOutside);
  }, []);

  const getInitials = (name) => {
    if (!name) return "";
    const words = name.trim().split(" ");
    if (words.length === 1) return words[0][0].toUpperCase();
    return (
      words[0][0].toUpperCase() +
      (words[1] ? words[1][0].toUpperCase() : "")
    );
  };

  const filteredMenu = useMemo(() => {
    return menuItems.filter((item) =>
      item.name.toLowerCase().includes(search.toLowerCase())
    );
  }, [search]);

  const handleLogout = () => {
    localStorage.removeItem("adminInfo");
    localStorage.removeItem("token");
    navigate("/admin/login");
  };

  return (
    <div className={design.layout.wrapper}>
      {/* 🔥 TOP NAVBAR */}
      <div className={design.layout.navbar}>
        <div className="flex items-center gap-3">
          {/* Mobile Menu Button */}
          <button
            onClick={() => setSidebarOpen(true)}
            className="lg:hidden text-2xl text-gray-700"
          >
            ☰
          </button>
        </div>

        <input
          type="text"
          placeholder="Search menu..."
          value={search}
          onChange={(e) => setSearch(e.target.value)}
          className={design.colors.input}
        />

        {/* Avatar + Dropdown */}
        <div className="relative" ref={dropdownRef}>
          <div
            onClick={() => setDropdownOpen(!dropdownOpen)}
            className="w-10 h-10 rounded-full bg-indigo-600 text-white flex items-center justify-center font-semibold cursor-pointer"
          >
            {getInitials(adminInfo?.name)}
          </div>

          <AnimatePresence>
            {dropdownOpen && (
              <motion.div
                initial={{ opacity: 0, y: 10 }}
                animate={{ opacity: 1, y: 0 }}
                exit={{ opacity: 0, y: 10 }}
                className="absolute right-0 mt-3 w-64 bg-white shadow-lg rounded-lg p-4 z-50"
              >
                <div className="border-b pb-3 mb-3">
                  <p className="font-semibold text-gray-800">
                    {adminInfo?.name}
                  </p>
                  <p className="text-sm text-gray-500">
                    {adminInfo?.email}
                  </p>
                </div>

                <div
                  onClick={() => navigate("/admin/profile")}
                  className="flex items-center gap-2 p-2 rounded-md hover:bg-gray-100 cursor-pointer text-sm"
                >
                  <User size={16} />
                  Profile
                </div>

                <div
                  onClick={handleLogout}
                  className="flex items-center gap-2 p-2 rounded-md hover:bg-gray-100 cursor-pointer text-sm text-red-500"
                >
                  <LogOut size={16} />
                  Logout
                </div>
              </motion.div>
            )}
          </AnimatePresence>
        </div>
      </div>

      {/* 🔥 BODY */}
      <div className="flex flex-1 overflow-hidden relative">
        {/* Overlay */}
        <AnimatePresence>
          {sidebarOpen && (
            <motion.div
              initial={{ opacity: 0 }}
              animate={{ opacity: 1 }}
              exit={{ opacity: 0 }}
              onClick={() => setSidebarOpen(false)}
              className="fixed inset-0 bg-black/40 z-40 lg:hidden"
            />
          )}
        </AnimatePresence>

        {/* Sidebar */}
        <motion.aside
          initial={false}
          animate={{ x: sidebarOpen ? 0 : -300 }}
          transition={{ duration: 0.3 }}
          className={`
            fixed lg:static
            top-0 left-0
            h-full lg:h-auto
            w-64
            z-50 lg:z-auto
            ${design.colors.sidebar}
            ${design.layout.sidebar}
            lg:translate-x-0
          `}
        >
          {/* Sidebar Header */}
          <div className="mb-6">
            <div className="flex items-center justify-between lg:block">
              <div>
                <h2 className="text-lg font-semibold text-white">
                  Admin Panel
                </h2>
                <p className="text-xs text-gray-400 mt-1">
                  Nahid Enterprise
                </p>
              </div>

              {/* Close Button (Mobile Only) */}
              <button
                onClick={() => setSidebarOpen(false)}
                className="text-white text-xl lg:hidden"
              >
                ✕
              </button>
            </div>
          </div>

          <nav className="space-y-2">
            {filteredMenu.length > 0 ? (
              filteredMenu.map((item, index) => {
                const Icon = item.icon;
                return (
                  <div
                    key={index}
                    className={`${design.layout.navItem} ${design.colors.hover}`}
                  >
                    <Icon size={18} />
                    {item.name}
                  </div>
                );
              })
            ) : (
              <p className="text-sm text-gray-400">No results</p>
            )}
          </nav>
        </motion.aside>

        {/* Content */}
        <div className={design.layout.content}>
          <h2 className="text-2xl font-bold mb-4">
            Welcome Back 👋
          </h2>
        </div>
      </div>
    </div>
  );
};

export default AdminDashboard;
